import { DetailedHTMLProps, InputHTMLAttributes } from 'react'
import styled, { css } from 'styled-components'

import { Body } from '../typography/Body'

const Container = styled.div(
  ({ theme: { color, spacing, boxShadow, borderRadius } }) => css`
    display: flex;
    flex-direction: column;
    padding-bottom: 0;
    label {
      color: ${color.label};
      padding-bottom: ${spacing.xxs};
      &:first-letter {
        text-transform: uppercase;
      }
    }

    input {
      outline: none;
      padding: 13px 16px;
      box-sizing: border-box;
      border-radius: ${borderRadius.xs};
      border: none;
      color: ${color.primaryText};
      background: ${color.inputBackground};
      margin: 0;
      &:placeholder {
        color: ${color.inputHint};
      }
      &:focus,
      &:hover {
        box-shadow: ${boxShadow.outerBorder};
      }
    }

    input:focus + label {
      color: ${color.labelActive};
    }
  `
)

const ErrorMessage = styled(Body)(
  ({ theme: { color, spacing } }) => css`
    color: ${color.error};
    margin-top: ${spacing.xxs};
    font-size: 12px;
    min-height: 16px;
  `
)

type InputProps = {
  label?: string
  value?: any
  onChange?: (data: any) => void
  error?: string
} & DetailedHTMLProps<InputHTMLAttributes<HTMLInputElement>, HTMLInputElement>

export const Input = ({ label = '', type = 'text', id, error, ...otherProps }: InputProps) => (
  <Container>
    {label && (
      <Body type="label" htmlFor={id}>
        {label}
      </Body>
    )}
    <input id={id} aria-label={label} type={type} {...otherProps} autoComplete="off" />
    <ErrorMessage>{error || ' '}</ErrorMessage>
  </Container>
)

import { useMemo } from 'react'

import { ShoppingCartItem } from '../ShoppingCartItem/ShoppingCartItem'
import { CartItem } from '../../../app-state/cart'
import { Body } from '../../typography/Body'
import { toCurrency } from '../../../helpers'

import {
  OrderSummaryContainer,
  BottomContainer,
  CartItemsContainer,
  StyledHeading,
} from './OrderSummary.styles'

type OrderSummaryProps = {
  cartItems: CartItem[]
}

export const OrderSummary = ({ cartItems }: OrderSummaryProps) => {
  const totalPrice = useMemo(
    () => cartItems.map((item) => item.quantity * item.price).reduce((acc, next) => acc + next, 0),
    [cartItems]
  )
  return (
    <>
      <OrderSummaryContainer>
        <StyledHeading level={3} $withMargin>
          Your order
        </StyledHeading>
        <CartItemsContainer>
          {cartItems.length > 0 ? (
            cartItems.map((item) => <ShoppingCartItem key={item.id} item={item} />)
          ) : (
            <Body>Your cart is empty.</Body>
          )}
        </CartItemsContainer>
        <BottomContainer>
          <Body>Total</Body>
          <StyledHeading level={2}>{toCurrency(totalPrice)}</StyledHeading>
        </BottomContainer>
      </OrderSummaryContainer>
    </>
  )
}

