    89→
    90→/**
    91→ * Primary UI component for user interaction
    92→ */
    93→export const Button: React.FC<React.PropsWithChildren<ButtonProperties>> = ({
    94→  children,
    95→  large = false,
    96→  clear = false,
    97→  round = false,
    98→  icon,
    99→  iconSize,
   100→  ...properties
   101→}: ButtonProperties) => {
   102→  const { color } = useTheme()
   103→
   104→  return (
   105→    <StyledButton
   106→      type="button"
   107→      $large={large}
   108→      $clear={clear}
   109→      $round={round}
